#include <stdio.h>
#include <string.h>

long long C[7][7];

int main() {
    // pre-compute binomial coefficients up to 6
    for (int n = 0; n <= 6; ++n) {
        C[n][0] = C[n][n] = 1;
        for (int k = 1; k < n; ++k) {
            C[n][k] = C[n-1][k-1] + C[n-1][k];
        }
    }
    int X, N;
    while (scanf("%d %d", &X, &N) == 2) {
        char s[55];
        long long ans = 0;
        // seat indices for the 9 compartments (0-based)
        int comp[9][6] = {
            {0,1,2,3,52,53},   // compartment 1
            {4,5,6,7,50,51},   // compartment 2
            {8,9,10,11,48,49}, // compartment 3
            {12,13,14,15,46,47},
            {16,17,18,19,44,45},
            {20,21,22,23,42,43},
            {24,25,26,27,40,41},
            {28,29,30,31,38,39},
            {32,33,34,35,36,37}
        };
        for (int i = 0; i < N; ++i) {
            scanf("%s", s);
            for (int c = 0; c < 9; ++c) {
                int free = 0;
                for (int p = 0; p < 6; ++p) {
                    if (s[comp[c][p]] == '0') ++free;
                }
                if (free >= X) ans += C[free][X];
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

