    static long[][] C = new long[7][7];
    static {
        for (int n = 0; n <= 6; n++) {
            C[n][0] = C[n][n] = 1;
            for (int k = 1; k < n; k++) C[n][k] = C[n-1][k-1] + C[n-1][k];
        }
    }
    static final int[][] COMP = {
        {0,1,2,3,52,53}, {4,5,6,7,50,51}, {8,9,10,11,48,49},
        {12,13,14,15,46,47}, {16,17,18,19,44,45}, {20,21,22,23,42,43},
        {24,25,26,27,40,41}, {28,29,30,31,38,39}, {32,33,34,35,36,37}
    };
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line;
        while ((line = br.readLine()) != null) {
            line = line.trim();
            if (line.isEmpty()) continue;
            StringTokenizer st = new StringTokenizer(line);
            int X = Integer.parseInt(st.nextToken());
            int N = Integer.parseInt(st.nextToken());
            long ans = 0;
            for (int i = 0; i < N; i++) {
                String s = br.readLine().trim();
                for (int c = 0; c < 9; c++) {
                    int free = 0;
                    for (int p = 0; p < 6; p++) if (s.charAt(COMP[c][p]) == '0') free++;
                    if (free >= X) ans += C[free][X];
                }
            }
            System.out.println(ans);
        }
    }
}

