#!/usr/bin/env python3
import sys

def precompute():
    C = [[0]*7 for _ in range(7)]
    for n in range(7):
        C[n][0] = C[n][n] = 1
        for k in range(1, n):
            C[n][k] = C[n-1][k-1] + C[n-1][k]
    return C

C = precompute()
# compartment seat indices (0-based)
COMP = [
    [0,1,2,3,52,53], [4,5,6,7,50,51], [8,9,10,11,48,49],
    [12,13,14,15,46,47], [16,17,18,19,44,45], [20,21,22,23,42,43],
    [24,25,26,27,40,41], [28,29,30,31,38,39], [32,33,34,35,36,37]
]

data = sys.stdin.read().strip().splitlines()
idx = 0
while idx < len(data):
    if not data[idx].strip():
        idx += 1
        continue
    X, N = map(int, data[idx].split())
    idx += 1
    ans = 0
    for _ in range(N):
        s = data[idx].strip()
        idx += 1
        for comp in COMP:
            free = sum(1 for pos in comp if s[pos] == '0')
            if free >= X:
                ans += C[free][X]
    print(ans)

