  C[n][0]=1n; C[n][n]=1n;
  for(let k=1;k<n;k++) C[n][k]=C[n-1][k-1]+C[n-1][k];
}
const COMP = [
  [0,1,2,3,52,53],[4,5,6,7,50,51],[8,9,10,11,48,49],
  [12,13,14,15,46,47],[16,17,18,19,44,45],[20,21,22,23,42,43],
  [24,25,26,27,40,41],[28,29,30,31,38,39],[32,33,34,35,36,37]
];
let outputs = [];
while (idx < input.length) {
  if (input[idx].trim() === '') { idx++; continue; }
  const [Xstr, Nstr] = input[idx].trim().split(/\s+/);
  const X = Number(Xstr), N = Number(Nstr);
